## 3. gRPC Proto 설계

**파일 위치:** `/protobuf/src/main/proto/profile/profile_service.proto`

```protobuf
syntax = "proto3";
package profile;

option java_multiple_files = true;
option java_package = "com.maum.backend.protobuf.profile";

// ──────────────────────────────────────────
// 서비스 정의
// ──────────────────────────────────────────

service ProfileService {
  rpc GetMyProfile(GetMyProfileRequest) returns (GetMyProfileResponse);
  rpc UpdateProfile(UpdateProfileRequest) returns (UpdateProfileResponse);
  rpc UpdateProfileImages(UpdateProfileImagesRequest) returns (UpdateProfileImagesResponse);
}

// ──────────────────────────────────────────
// 공통 메시지
// ──────────────────────────────────────────

message ProfileProto {
  string user_id = 1;
  string nickname = 2;
  optional string bio = 3;
  string birth_date = 4;
  string gender = 5;
  optional int32 height = 6;
  optional string job = 7;
  optional string region = 8;
  repeated ProfileImageProto profile_images = 9;
  repeated string interests = 10;
  string updated_at = 11;
}

message ProfileImageProto {
  string id = 1;
  string url = 2;
  int32 order = 3;
  bool is_primary = 4;
}

// ──────────────────────────────────────────
// GetMyProfile
// ──────────────────────────────────────────

message GetMyProfileRequest {
  string user_id = 1;
}

message GetMyProfileResponse {
  ProfileProto profile = 1;
}

// ──────────────────────────────────────────
// UpdateProfile
// ──────────────────────────────────────────

message UpdateProfileRequest {
  string user_id = 1;
  optional string nickname = 2;
  optional string bio = 3;
  optional int32 height = 4;
  optional string job = 5;
  optional string region = 6;
  repeated string interests = 7;
  bool has_interests = 8;  // interests 배열이 명시적으로 전달됐는지 여부
}

message UpdateProfileResponse {
  ProfileProto profile = 1;
}

// ──────────────────────────────────────────
// UpdateProfileImages
// ──────────────────────────────────────────

message UpdateProfileImagesRequest {
  string user_id = 1;
  repeated ProfileImageInput images = 2;
}

message ProfileImageInput {
  optional string id = 1;  // 기존 이미지면 ID 포함, 신규면 생략
  string url = 2;
  int32 order = 3;
  bool is_primary = 4;
}

message UpdateProfileImagesResponse {
  repeated ProfileImageProto profile_images = 1;
}
```

