    fun updateProfileImages(userId: String, input: UpdateProfileImagesInput): UpdateProfileImagesResponse {
        val request = UpdateProfileImagesRequest.newBuilder()
            .setUserId(userId)
            .addAllImages(input.images.map { it.toProto() })
            .build()
        return try {
            stub.updateProfileImages(request)
        } catch (e: StatusRuntimeException) {
            throw CustomGraphQLException(e.trailers!!, e.status.description)
        }
    }
}
