## 5. gRPC 서버 구현 청사진

**파일 위치:** `/profile-service/src/main/kotlin/com/maum/backend/controller/ProfileGrpcService.kt`

```kotlin
@GrpcService
class ProfileGrpcService(
    private val profileDomainService: ProfileDomainService,
) : ProfileServiceGrpc.ProfileServiceImplBase() {

    override fun getMyProfile(
        request: GetMyProfileRequest,
        responseObserver: StreamObserver<GetMyProfileResponse>,
    ) {
        val profile = profileDomainService.getProfile(request.userId)
        responseObserver.onNext(
            GetMyProfileResponse.newBuilder()
                .setProfile(profile.toProto())
                .build()
        )
        responseObserver.onCompleted()
    }

    override fun updateProfile(
        request: UpdateProfileRequest,
        responseObserver: StreamObserver<UpdateProfileResponse>,
    ) {
        val updated = profileDomainService.updateProfile(request)
        responseObserver.onNext(
            UpdateProfileResponse.newBuilder()
                .setProfile(updated.toProto())
                .build()
        )
        responseObserver.onCompleted()
    }

    override fun updateProfileImages(
        request: UpdateProfileImagesRequest,
        responseObserver: StreamObserver<UpdateProfileImagesResponse>,
    ) {
        val images = profileDomainService.updateProfileImages(request.userId, request.imagesList)
        responseObserver.onNext(
            UpdateProfileImagesResponse.newBuilder()
                .addAllProfileImages(images.map { it.toProto() })
                .build()
        )
        responseObserver.onCompleted()
    }
}
